function solve(grid: number[][], x: number, y: number, k: number): number[][] {
    // Create a copy of the grid to avoid modifying the original
    let newGrid = grid.map(row => [...row]);

    // Extract the submatrix rows
    let submatrixRows = [];
    for (let i = x; i < x + k; i++) {
        let row = newGrid[i];
        let subRow = row.slice(y, y + k);
        submatrixRows.push(subRow);
    }

    // Reverse the submatrix rows
    submatrixRows = submatrixRows.reverse();

    // Put the reversed submatrix rows back into the grid
    for (let i = 0; i < k; i++) {
        let row = newGrid[x + i];
        let subRow = submatrixRows[i];
        for (let j = 0; j < k; j++) {
            row[y + j] = subRow[j];
        }
    }

    return newGrid;
}

